 1	import type { FC } from 'react';
 2	
 3	import { Text, TextVariants } from '@patternfly/react-core';
 4	import { useForkliftTranslation } from '@utils/i18n';
 5	
 6	const NodeFieldsDescriptionText: FC = () => {
 7	  const { t } = useForkliftTranslation();
 8	  return (
 9	    <>
10	      <Text className="text-muted" component={TextVariants.p}>
11	        {t(
12	          'Field selectors let you select Nodes based on the value of one or more resource fields.',
13	        )}
14	      </Text>
15	      <Text className="text-muted" component={TextVariants.p}>
16	        {t(
17	          'Note that for Node field expressions, entering a full path is required in the "Key" field (e.g. "metadata.name: value").',
18	        )}
19	      </Text>
20	      <Text className="text-muted" component={TextVariants.p}>
21	        {t('Some fields may not be supported.')}
22	      </Text>
23	    </>
24	  );
25	};
26	export default NodeFieldsDescriptionText;

